mapper.select:
select count(materials_id)
from course_materials cm
inner join course co on cm.course_id = co.course_id

    (co.professor = #{loginID}
    OR co.sub_prof = #{loginID})

        AND cm.course_id = #{course_id}

select course_id
     , title as course_title
from course
where professor = #{loginID}
    or sub_prof = #{loginID}

mapper.insert:
insert into course_materials
( title
, content
, register_date
, course_id
, file_id)
VALUES
( #{title}
, #{content}
, #{register_date}
, #{course_id}
, #{file_id})

mapper.select:
select cm.materials_id as materials_id , cm.title , co.title AS course_title , cm.content , register_date , update_date , cm.course_id , cm.file_id , fl.name as file_name , fl.logical_path from course_materials cm inner join course co on cm.course_id = co.course_id left join file fl on cm.file_id = fl.file_id
(co.professor = #{loginID} OR co.sub_prof = #{loginID})
AND cm.course_id = #{course_id}
order by cm.materials_id DESC Limit #{start}, #{limit}

mapper.update:
update course_materials
set title       = #{title}
  , content     = #{content}
  , update_date = #{update_date}
where materials_id = #{materials_id}
